SWEP.PrintName = "Combine Grenade"SWEP.Category = "Half-Life 2"SWEP.Author		= "VALVe"SWEP.DrawWeaponInfoBox	= falseSWEP.BounceWeaponIcon = false SWEP.Spawnable= trueSWEP.AdminSpawnable= trueSWEP.AdminOnly = falseSWEP.ViewModelFOV = 90SWEP.ViewModel = "models/weapons/c_comgrenade.mdl"SWEP.WorldModel = "models/weapons/w_comgrenade.mdl"SWEP.ViewModelFlip = falseSWEP.BobScale = 1SWEP.SwayScale = 0SWEP.AutoSwitchTo = falseSWEP.AutoSwitchFrom = falseSWEP.Weight = 0SWEP.Slot = 4SWEP.SlotPos = 1SWEP.UseHands = trueSWEP.HoldType = "grenade"SWEP.FiresUnderwater = trueSWEP.DrawCrosshair = trueSWEP.DrawAmmo = trueSWEP.CSMuzzleFlashes = 1SWEP.Base = "weapon_base"--------------------------------------------------------------------------------|SWEP.Throw = 0SWEP.ThrowN = 0SWEP.ThrowTimer = CurTime()SWEP.Idle = 0SWEP.IdleTimer = CurTime()--------------------------------------------------------------------------------|SWEP.Primary.ClipSize = -1SWEP.Primary.DefaultClip = 1SWEP.Primary.MaxAmmo = 3SWEP.Primary.Automatic = trueSWEP.Primary.Ammo = "ComGren_CETS"SWEP.Primary.TakeAmmo = 1SWEP.Primary.Delay = 1SWEP.Primary.Force = 750--------------------------------------------------------------------------------|SWEP.Secondary.ClipSize = -1SWEP.Secondary.DefaultClip = -1SWEP.Secondary.Automatic = trueSWEP.Secondary.Ammo = "none"SWEP.Secondary.Force = 250--------------------------------------------------------------------------------|SWEP.GrenadeType = "obj_vj_cets_extractor"--------------------------------------------------------------------------------|function SWEP:DrawWorldModel()	local owner = self:GetOwner() 	if IsValid( owner ) and ( owner:IsPlayer() or owner:IsNPC() ) then		owner:SetupBones() 		local attachIndex = owner:LookupAttachment( "anim_attachment_RH" ) 		if attachIndex and attachIndex > 0 then			local attachData = owner:GetAttachment( attachIndex ) 			if attachData then				local interpCorrection = owner:GetVelocity() * ( FrameTime() - 0 ) 				local posOffset = Vector( 1, -1, 1 )				local angOffset = Angle( 0, 0, 0 )				local ang = attachData.Ang				local finalPos = attachData.Pos + interpCorrection + ang:Forward() * posOffset.x + ang:Right()* posOffset.y + ang:Up() * posOffset.z				local finalAng = ang + angOffset				self:SetRenderOrigin( finalPos )				self:SetRenderAngles( finalAng )			end		end	end 	self:DrawModel()end--------------------------------------------------------------------------------|function SWEP:Initialize()	self:SetWeaponHoldType( self.HoldType )	self.Idle = 0	self.IdleTimer = CurTime() + 1end--------------------------------------------------------------------------------|function SWEP:Deploy()	self:SetWeaponHoldType( self.HoldType )	self.Weapon:SendWeaponAnim( ACT_VM_DRAW )	self:SetNextPrimaryFire( CurTime() + 0.5 )	self:SetNextSecondaryFire( CurTime() + 0.5 )	self.Throw = 0	self.ThrowTimer = CurTime()	self.Idle = 0	self.IdleTimer = CurTime() + self.Owner:GetViewModel():SequenceDuration()	return trueend--------------------------------------------------------------------------------|function SWEP:Holster()	self.Idle = 0	self.IdleTimer = CurTime()	if self.Weapon:Ammo1() <= 0 then		if SERVER then			self.Owner:DropWeapon( self.Weapon )			self.Weapon:Remove()		end	end	return trueend--------------------------------------------------------------------------------|function SWEP:PrimaryAttack()	if !( self.Throw == 0 ) then return end	if self.Weapon:Ammo1() <= 0 then return end	self.Weapon:SendWeaponAnim( ACT_VM_PULLPIN )	self:SetNextPrimaryFire( CurTime() + self.Primary.Delay )	self:SetNextSecondaryFire( CurTime() + self.Primary.Delay )	self.Throw = 1	self.ThrowTimer = CurTime() + self.Primary.Delay	self.Idle = 1end--------------------------------------------------------------------------------|function SWEP:SecondaryAttack()	if !( self.ThrowN == 0 ) then return end	if self.Weapon:Ammo1() <= 0 then return end	self.Weapon:SendWeaponAnim( ACT_VM_PULLPIN )	self:SetNextPrimaryFire( CurTime() + self.Primary.Delay )	self:SetNextSecondaryFire( CurTime() + self.Primary.Delay )	self.ThrowN = 1	self.ThrowTimer = CurTime() + self.Primary.Delay	self.Idle = 1end--------------------------------------------------------------------------------|function SWEP:Think()	local function LaunchGrenade(force)		if SERVER then			local entity = ents.Create(self.GrenadeType)			entity:SetOwner(self.Owner)			if IsValid(entity) then				local Forward = self.Owner:EyeAngles():Forward()				local Right = self.Owner:EyeAngles():Right()				entity:SetPos(self.Owner:GetShootPos() + Forward * 8 + Right * 4)				entity:SetAngles(self.Owner:EyeAngles())				entity:Spawn()				local phys = entity:GetPhysicsObject()				phys:SetVelocity(self.Owner:GetAimVector() * force)				phys:AddAngleVelocity(Vector(math.Rand(-500,500), math.Rand(-500,500), math.Rand(-500,500)))			end		end		self.Weapon:SendWeaponAnim(ACT_VM_THROW)		self.Owner:SetAnimation(PLAYER_ATTACK1)		self:TakePrimaryAmmo(self.Primary.TakeAmmo)		self.ThrowTimer = CurTime() + self.Primary.Delay	end	if self.Throw == 1 and self.ThrowTimer <= CurTime() and !self.Owner:KeyDown(IN_ATTACK) then		LaunchGrenade(self.Primary.Force)		self.Throw = 2	end	if self.ThrowN == 1 and self.ThrowTimer <= CurTime() and !self.Owner:KeyDown(IN_ATTACK2) then		LaunchGrenade(self.Secondary.Force)		self.ThrowN = 2	end	if self.Idle == 0 and self.IdleTimer <= CurTime() then		if SERVER then self.Weapon:SendWeaponAnim(ACT_VM_IDLE) end		self.Idle = 1	end	if self.Weapon:Ammo1() > self.Primary.MaxAmmo then		self.Owner:SetAmmo(self.Primary.MaxAmmo, self.Primary.Ammo)	end	if (self.Throw == 2 or self.ThrowN == 2) and self.ThrowTimer <= CurTime() then		if self.Weapon:Ammo1() > 0 then			self.Weapon:SendWeaponAnim(ACT_VM_DRAW)			self.Throw, self.ThrowN, self.ThrowTimer = 0, 0, CurTime()			self.Idle, self.IdleTimer = 0, CurTime() + self.Owner:GetViewModel():SequenceDuration()		else			if SERVER then				self.Owner:DropWeapon(self.Weapon)				self.Weapon:Remove()			end		end	endend--------------------------------------------------------------------------------|function SWEP:Reload() end